create table dirkspzm32.isi_resource_var (
    sid                   varchar2(2 char) not null enable,
    res_id                number(*, 0) not null enable,
    variante              number(*, 5) not null enable,
    status                varchar2(10 char) not null enable,
    datum_von             date not null enable,
    datum_bis             date not null enable,
    firma_nr              number(6, 0) default 1 not null enable,
    lgr_platz             number(*, 5),
    zyk_prod_res          number(*, 5),
    zyk_prod_ges          number(*, 5) default 0 not null enable,
    std_prod_res          number(*, 5) default 0 not null enable,
    std_prod_ges          number(*, 5) default 0 not null enable,
    zyklus_typ            varchar2(50 char),
    im_bestand_seit       date default sysdate not null enable,
    letzte_wartg_am       date,
    letzte_wartg_zykl_ges number(*, 5),
    artkel_id             number(*, 0),
    res_container         varchar2(1 char) default 'F' not null enable,
    menge_in_container    number(*, 3),
    inspektion_info       varchar2(255 char)
);

alter table dirkspzm32.isi_resource_var
    add constraint pk_resource_var
        primary key ( sid,
                      variante,
                      res_id )
            using index enable;


